import { test as base, Page } from '@playwright/test';

export const APP_URL = 'https://hey-chill.vercel.app';

/**
 * Script injected before page load to replace Web Speech API with a
 * controllable mock. Exposes window.__mockRecognition for test control.
 */
export const MOCK_SPEECH_SCRIPT = `
(function() {
  class MockSpeechRecognition {
    constructor() {
      this.continuous = false;
      this.interimResults = false;
      this.lang = '';
      this.maxAlternatives = 1;
      this.onstart = null;
      this.onresult = null;
      this.onerror = null;
      this.onend = null;
      this._started = false;
      window.__mockRecognition = this;
    }

    start() {
      this._started = true;
      if (this.onstart) this.onstart();
    }

    stop() {
      this._started = false;
      if (this.onend) this.onend();
    }

    /** Simulate a speech result event */
    _fireResult(transcript, isFinal) {
      if (!this.onresult) return;
      const results = [[{ transcript: transcript }]];
      results[0].isFinal = !!isFinal;
      results.length = 1;
      this.onresult({ resultIndex: 0, results: results });
    }

    /** Simulate a recognition error */
    _fireError(errorCode) {
      if (this.onerror) this.onerror({ error: errorCode });
    }

    /** Simulate recognition ending on its own (e.g. network cut) */
    _fireEnd() {
      if (this.onend) this.onend();
    }
  }

  window.SpeechRecognition = MockSpeechRecognition;
  window.webkitSpeechRecognition = MockSpeechRecognition;
})();
`;

