/**
 * Settings Modal Tests
 * Covers opening/closing the settings panel and webhook URL persistence.
 */
import { test, expect } from './fixtures';

test.describe('Settings modal', () => {
  test('opens when settings button is clicked', async ({ mockPage: page }) => {
    await page.click('#settings-btn');
    await expect(page.locator('#modal-overlay')).not.toHaveAttribute('hidden');
    await expect(page.locator('h2#modal-title')).toHaveText('Settings');
  });

  test('closes when X button is clicked', async ({ mockPage: page }) => {
    await page.click('#settings-btn');
    await expect(page.locator('#modal-overlay')).not.toHaveAttribute('hidden');
    await page.click('#modal-close');
    await expect(page.locator('#modal-overlay')).toHaveAttribute('hidden', '');
  });

  test('closes when Escape key is pressed', async ({ mockPage: page }) => {
    await page.click('#settings-btn');
    await expect(page.locator('#modal-overlay')).not.toHaveAttribute('hidden');
    await page.keyboard.press('Escape');
    await expect(page.locator('#modal-overlay')).toHaveAttribute('hidden', '');
  });

  test('closes when clicking outside the modal', async ({ mockPage: page }) => {
    await page.click('#settings-btn');
    await expect(page.locator('#modal-overlay')).not.toHaveAttribute('hidden');
    // Click on the overlay backdrop (not the inner modal box)
    await page.locator('#modal-overlay').click({ position: { x: 5, y: 5 } });
    await expect(page.locator('#modal-overlay')).toHaveAttribute('hidden', '');
  });

  test('webhook URL field accepts input', async ({ mockPage: page }) => {
    await page.click('#settings-btn');
    await page.fill('#webhook-url', 'https://example.com/hook');
    await expect(page.locator('#webhook-url')).toHaveValue('https://example.com/hook');
  });

  test('saving webhook URL persists to localStorage', async ({ mockPage: page }) => {
    await page.click('#settings-btn');
    await page.fill('#webhook-url', 'https://example.com/hook');
    await page.click('#save-settings');

    const stored = await page.evaluate(() => localStorage.getItem('webhookUrl'));
    expect(stored).toBe('https://example.com/hook');
  });

  test('saved URL is pre-populated when settings reopened', async ({ mockPage: page }) => {
    // Set via localStorage directly
    await page.evaluate(() => localStorage.setItem('webhookUrl', 'https://saved.example.com/hook'));
    await page.click('#settings-btn');
    await expect(page.locator('#webhook-url')).toHaveValue('https://saved.example.com/hook');
  });

  test('Save button closes the modal', async ({ mockPage: page }) => {
    await page.click('#settings-btn');
    await page.fill('#webhook-url', 'https://example.com/hook');
    await page.click('#save-settings');
    await expect(page.locator('#modal-overlay')).toHaveAttribute('hidden', '');
  });
});

