/**
 * Transcription Display Tests
 * Covers live transcript updates, interim vs final results, and HTML escaping.
 */
import { test, expect, startRecording, stopRecording, simulateSpeech, simulateInterim } from './fixtures';

test.describe('Transcription', () => {
  test('live text starts as "Listening…" when recording begins', async ({ mockPage: page }) => {
    await startRecording(page);
    await expect(page.locator('#live-text')).toHaveText('Listening…');
  });

  test('interim transcript updates live text', async ({ mockPage: page }) => {
    await startRecording(page);
    await simulateInterim(page, 'hello');
    await expect(page.locator('#live-text')).toHaveText('hello');
  });

  test('final transcript updates live text', async ({ mockPage: page }) => {
    await startRecording(page);
    await simulateSpeech(page, 'hello world');
    await expect(page.locator('#live-text')).toHaveText('hello world');
  });

  test('multiple final results are concatenated', async ({ mockPage: page }) => {
    await startRecording(page);
    await simulateSpeech(page, 'hello');
    await simulateSpeech(page, 'world');
    // The app appends with a space: 'hello ' + 'world '
    await expect(page.locator('#live-text')).toContainText('hello');
    await expect(page.locator('#live-text')).toContainText('world');
  });

  test('transcript bar shows correct text after recording stops', async ({ mockPage: page }) => {
    await startRecording(page);
    await simulateSpeech(page, 'test message');
    await stopRecording(page);
    await expect(page.locator('#transcript-text')).toHaveText('test message');
  });

  test('HTML special characters are escaped in transcript display', async ({ mockPage: page }) => {
    await startRecording(page);
    await simulateSpeech(page, '<script>alert(1)</script>');
    await stopRecording(page);
    // The text content should be the raw string, not executed HTML
    await expect(page.locator('#transcript-text')).toHaveText('<script>alert(1)</script>');
    // But the DOM should not contain a script element from user input
    const scriptCount = await page.locator('#messages script').count();
    expect(scriptCount).toBe(0);
  });

  test('discard button hides the transcript bar', async ({ mockPage: page }) => {
    await startRecording(page);
    await simulateSpeech(page, 'discard me');
    await stopRecording(page);
    await expect(page.locator('#transcript-bar')).toBeVisible();
    await page.click('#discard-btn');
    await expect(page.locator('#transcript-bar')).toBeHidden();
  });

  test('live transcript panel is hidden after stopping', async ({ mockPage: page }) => {
    await startRecording(page);
    await simulateSpeech(page, 'something');
    await stopRecording(page);
    await expect(page.locator('#live-transcript')).toBeHidden();
  });
});

