/**
 * Webhook Send Tests
 * Uses page.route() to intercept fetch calls — no real webhook needed.
 */
import { test, expect, startRecording, stopRecording, simulateSpeech } from './fixtures';

const WEBHOOK = 'https://example.com/webhook/hey-chill';

test.describe('Webhook send', () => {
  test('Send button POSTs transcript to the configured webhook URL', async ({ mockPage: page }) => {
    // Intercept the webhook call
    let capturedRequest: { url: string; method: string; body: any } | null = null;
    await page.route(WEBHOOK, async (route) => {
      const req = route.request();
      capturedRequest = {
        url: req.url(),
        method: req.method(),
        body: JSON.parse(req.postData() || '{}'),
      };
      await route.fulfill({ status: 200, body: 'ok' });
    });

    await page.evaluate((url) => localStorage.setItem('webhookUrl', url), WEBHOOK);
    await page.reload();

    await startRecording(page);
    await simulateSpeech(page, 'send this message');
    await stopRecording(page);

    await page.click('#send-btn');

    await expect.poll(() => capturedRequest).not.toBeNull();
    expect(capturedRequest!.method).toBe('POST');
    expect(capturedRequest!.body.text).toBe('send this message');
  });

  test('webhook payload contains source field set to "hey-chill"', async ({ mockPage: page }) => {
    let body: any = null;
    await page.route(WEBHOOK, async (route) => {
      body = JSON.parse(route.request().postData() || '{}');
      await route.fulfill({ status: 200, body: 'ok' });
    });

    await page.evaluate((url) => localStorage.setItem('webhookUrl', url), WEBHOOK);
    await page.reload();

    await startRecording(page);
    await simulateSpeech(page, 'source test');
    await stopRecording(page);
    await page.click('#send-btn');

    await expect.poll(() => body).not.toBeNull();
    expect(body.source).toBe('hey-chill');
  });

  test('webhook payload contains a timestamp field', async ({ mockPage: page }) => {
    let body: any = null;
    await page.route(WEBHOOK, async (route) => {
      body = JSON.parse(route.request().postData() || '{}');
      await route.fulfill({ status: 200, body: 'ok' });
    });

    await page.evaluate((url) => localStorage.setItem('webhookUrl', url), WEBHOOK);
    await page.reload();

    await startRecording(page);
    await simulateSpeech(page, 'timestamp test');
    await stopRecording(page);
    await page.click('#send-btn');

    await expect.poll(() => body).not.toBeNull();
    expect(body.timestamp).toBeTruthy();
    expect(() => new Date(body.timestamp)).not.toThrow();
  });

  test('message appears in history with "Sent" status on 200 response', async ({ mockPage: page }) => {
    await page.route(WEBHOOK, (route) => route.fulfill({ status: 200, body: 'ok' }));
    await page.evaluate((url) => localStorage.setItem('webhookUrl', url), WEBHOOK);
    await page.reload();

    await startRecording(page);
    await simulateSpeech(page, 'sent message');
    await stopRecording(page);
    await page.click('#send-btn');

    const msg = page.locator('.message').first();
    await expect(msg).toBeVisible();
    await expect(msg.locator('.message-text')).toHaveText('sent message');
    await expect(msg.locator('.message-status')).toHaveText('Sent');
  });

  test('message shows "Failed" status on non-2xx response', async ({ mockPage: page }) => {
    await page.route(WEBHOOK, (route) => route.fulfill({ status: 500, body: 'error' }));
    await page.evaluate((url) => localStorage.setItem('webhookUrl', url), WEBHOOK);
    await page.reload();

    await startRecording(page);
    await simulateSpeech(page, 'failing message');
    await stopRecording(page);
    await page.click('#send-btn');

    const msg = page.locator('.message').first();
    await expect(msg.locator('.message-status')).toHaveText('Failed');
  });

  test('message shows "Failed" status on network error', async ({ mockPage: page }) => {
    await page.route(WEBHOOK, (route) => route.abort('failed'));
    await page.evaluate((url) => localStorage.setItem('webhookUrl', url), WEBHOOK);
    await page.reload();

    await startRecording(page);
    await simulateSpeech(page, 'network error');
    await stopRecording(page);
    await page.click('#send-btn');

    const msg = page.locator('.message').first();
    await expect(msg.locator('.message-status')).toHaveText('Failed');
  });

  test('message shows "No webhook set" when no webhook URL is configured', async ({ mockPage: page }) => {
    // Ensure no webhook URL in localStorage
    await page.evaluate(() => localStorage.removeItem('webhookUrl'));
    await page.reload();

    await startRecording(page);
    await simulateSpeech(page, 'no webhook');
    await stopRecording(page);
    await page.click('#send-btn');

    const msg = page.locator('.message').first();
    await expect(msg.locator('.message-status')).toHaveText('No webhook set');
  });

  test('Discard button discards transcript without making a network request', async ({ mockPage: page }) => {
    let requestMade = false;
    await page.route('**/*', async (route) => {
      if (route.request().method() === 'POST') requestMade = true;
      await route.continue();
    });

    await startRecording(page);
    await simulateSpeech(page, 'do not send');
    await stopRecording(page);
    await page.click('#discard-btn');

    // No message in history
    await expect(page.locator('.message')).toHaveCount(0);
    expect(requestMade).toBe(false);
  });

  test('sent message text is HTML-escaped in the DOM', async ({ mockPage: page }) => {
    await page.route(WEBHOOK, (route) => route.fulfill({ status: 200, body: 'ok' }));
    await page.evaluate((url) => localStorage.setItem('webhookUrl', url), WEBHOOK);
    await page.reload();

    await startRecording(page);
    await simulateSpeech(page, '<b>bold</b>');
    await stopRecording(page);
    await page.click('#send-btn');

    const msg = page.locator('.message').first();
    // Text content should be the literal string, not rendered HTML
    await expect(msg.locator('.message-text')).toHaveText('<b>bold</b>');
    // No <b> element should be injected inside message text
    await expect(msg.locator('.message-text b')).toHaveCount(0);
  });

  test('empty messages area is hidden once a message is added', async ({ mockPage: page }) => {
    await page.route(WEBHOOK, (route) => route.fulfill({ status: 200, body: 'ok' }));
    await page.evaluate((url) => localStorage.setItem('webhookUrl', url), WEBHOOK);
    await page.reload();

    await expect(page.locator('#messages-empty')).toBeVisible();

    await startRecording(page);
    await simulateSpeech(page, 'hide empty state');
    await stopRecording(page);
    await page.click('#send-btn');

    await expect(page.locator('#messages-empty')).toBeHidden();
  });
});

