/**
 * PWA Tests
 * Verifies manifest, service worker registration, and installability criteria.
 */
import { test as base, expect } from '@playwright/test';
import { APP_URL, MOCK_SPEECH_SCRIPT } from './fixtures';

const test = base;

test.describe('PWA manifest', () => {
  test('manifest.json is accessible', async ({ page }) => {
    const res = await page.request.get(`${APP_URL}/manifest.json`);
    expect(res.status()).toBe(200);
  });

  test('manifest has correct name and short_name', async ({ page }) => {
    const res = await page.request.get(`${APP_URL}/manifest.json`);
    const manifest = await res.json();
    expect(manifest.name).toBe('Hey Chill');
    expect(manifest.short_name).toBe('Chill');
  });

  test('manifest has display: standalone', async ({ page }) => {
    const res = await page.request.get(`${APP_URL}/manifest.json`);
    const manifest = await res.json();
    expect(manifest.display).toBe('standalone');
  });

  test('manifest has at least two icons', async ({ page }) => {
    const res = await page.request.get(`${APP_URL}/manifest.json`);
    const manifest = await res.json();
    expect(Array.isArray(manifest.icons)).toBe(true);
    expect(manifest.icons.length).toBeGreaterThanOrEqual(2);
  });

  test('manifest has start_url set to "/"', async ({ page }) => {
    const res = await page.request.get(`${APP_URL}/manifest.json`);
    const manifest = await res.json();
    expect(manifest.start_url).toBe('/');
  });

  test('manifest icons include 192x192 and 512x512 sizes', async ({ page }) => {
    const res = await page.request.get(`${APP_URL}/manifest.json`);
    const manifest = await res.json();
    const sizes = manifest.icons.map((i: any) => i.sizes);
    expect(sizes).toContain('192x192');
    expect(sizes).toContain('512x512');
  });
});

test.describe('PWA service worker', () => {
  test('service worker script is accessible', async ({ page }) => {
    const res = await page.request.get(`${APP_URL}/sw.js`);
    expect(res.status()).toBe(200);
  });

  test('service worker is registered after page load', async ({ page }) => {
    await page.addInitScript(MOCK_SPEECH_SCRIPT);
    await page.goto(APP_URL);

    // Wait for service worker to register
    const swState = await page.evaluate(async () => {
      if (!('serviceWorker' in navigator)) return 'unsupported';
      const reg = await navigator.serviceWorker.getRegistration('/');
      return reg ? reg.scope : 'not-registered';
    });

    expect(swState).not.toBe('unsupported');
    expect(swState).not.toBe('not-registered');
  });
});

test.describe('PWA meta tags', () => {
  test('page links to manifest.json', async ({ page }) => {
    await page.addInitScript(MOCK_SPEECH_SCRIPT);
    await page.goto(APP_URL);
    const manifestHref = await page.locator('link[rel="manifest"]').getAttribute('href');
    expect(manifestHref).toBeTruthy();
  });
});

