  outline-offset: 4px;
}

.mic-btn.recording {
  background: linear-gradient(145deg, var(--accent), #c0392b);
  box-shadow:
    0 4px 32px var(--accent-glow),
    0 0 0 1px rgba(233, 69, 96, 0.3);
  animation: mic-glow 1.4s ease-in-out infinite alternate;
}

@keyframes mic-glow {
  from { box-shadow: 0 4px 24px var(--accent-glow), 0 0 0 1px rgba(233, 69, 96, 0.3); }
  to   { box-shadow: 0 4px 48px rgba(233, 69, 96, 0.7), 0 0 0 1px rgba(233, 69, 96, 0.5); }
}

.mic-icon {
  width: 36px;
  height: 36px;
  transition: transform var(--transition);
}

.mic-btn.recording .mic-icon {
  transform: scale(1.1);
}

/* ===== Not supported ===== */
.not-supported {
  margin: 0 20px 20px;
  background: rgba(255, 80, 80, 0.1);
  border: 1px solid rgba(255, 80, 80, 0.25);
  border-radius: var(--radius);
  padding: 14px 16px;
  text-align: center;
  font-size: 0.9rem;
  color: #ff9999;
}

/* ===== Modal ===== */
.modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.65);
  backdrop-filter: blur(4px);
  -webkit-backdrop-filter: blur(4px);
  display: flex;
  align-items: flex-end;
  justify-content: center;
  z-index: 100;
  animation: fade-in 0.2s ease;
}

.modal-overlay[hidden] {
  display: none;
}

.modal {
  background: var(--bg-2);
  border: 1px solid var(--border);
  border-radius: var(--radius) var(--radius) 0 0;
  width: 100%;
  max-width: 480px;
  padding: 0;
  animation: slide-modal 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

@media (min-height: 600px) {
  .modal-overlay {
    align-items: center;
  }
  .modal {
    border-radius: var(--radius);
    max-width: 420px;
  }
}

@keyframes slide-modal {
  from { transform: translateY(40px); opacity: 0; }
  to   { transform: translateY(0); opacity: 1; }
}

.modal-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 20px 20px 16px;
  border-bottom: 1px solid var(--border);
}

.modal-header h2 {
  font-size: 1.1rem;
  font-weight: 600;
}

.modal-body {
  padding: 20px;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.modal-body label {
  font-size: 0.85rem;
  color: var(--text-muted);
  font-weight: 500;
}

.modal-body input {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  color: var(--text);
  font-size: 0.95rem;
  padding: 12px 14px;
  width: 100%;
  transition: border-color var(--transition);
  font-family: inherit;
}

.modal-body input::placeholder {
  color: var(--text-muted);
}

.modal-body input:focus {
  outline: none;
  border-color: var(--accent);
  box-shadow: 0 0 0 2px rgba(233, 69, 96, 0.15);
}

.field-hint {
  font-size: 0.78rem;
  color: var(--text-muted);
}

.modal-footer {
  padding: 16px 20px 24px;
  display: flex;
  justify-content: flex-end;
}

/* ===== Utilities ===== */
